//! Auto-generated by the spec-word-compliance workflow.
//!
//! Area: "Page geometry: pgSz and pgMar (size, orientation, margins, gutter)".
//!
//! Each `#[test]` encodes a Word-compliance constraint mined from
//! ECMA-376 / ISO 29500-1 / MS-OI29500 for the section-properties page-geometry
//! children (`w:pgSz`, `w:pgMar`, `w:rtlGutter`, `w:docGrid`). A FAILING
//! assertion means stemma DIVERGES from Word — that is a real compliance gap to
//! be traced to its source, NOT something to make pass by weakening the test.
//!
//! Methodology guard (consumption vs. save):
//!   * stemma round-trips UNTOUCHED content byte-verbatim. So `reserialize()` of
//!     an unedited document reflects stemma's verbatim-preservation contract, not
//!     Word's render-time normalization.
//!   * `xmlContains` / ordered-`contains` checks here are used only for markup
//!     stemma's serializer ACTIVELY governs: child/element ORDERING (Annex A /
//!     EG_SectPrContents xsd:sequence) and verbatim signed-token preservation of
//!     a value Word keeps on save.
//!   * Consumption rules ("code has no meaning", "code never sets size") are
//!     asserted on the READ side (`read_accepted().to_text()`), never on XML.
//!   * "Opens-clean" uses `stemma::api::validate`.

use std::io::Write;

use stemma::ExportOptions;
use stemma::api::Document;
use zip::write::FileOptions;

// ─── Prelude: minimal-DOCX plumbing (mirrors the shared spec-suite prelude) ────

/// Build a valid minimal `.docx`. `body_xml` is wrapped in
/// `<w:document><w:body>…</w:body></w:document>`. Each `(part_name, content)` in
/// `extra_parts` (e.g. `("word/styles.xml", "<w:styles…/>")`) is added to the
/// archive and given an Override in `[Content_Types].xml`.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content type for each extra part, keyed by the part's file name suffix.
    fn override_for(part_name: &str) -> String {
        let ct = if part_name.ends_with("styles.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
        } else if part_name.ends_with("numbering.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
        } else {
            "application/xml"
        };
        format!(r#"<Override PartName="/{part_name}" ContentType="{ct}"/>"#)
    }

    let mut overrides = String::new();
    for (part_name, _) in extra_parts {
        overrides.push_str(&override_for(part_name));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#;

    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part_name, content) in extra_parts {
            zip.start_file(*part_name, opts).unwrap();
            zip.write_all(content.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let archive = stemma::docx::DocxArchive::read(docx).expect("read docx archive");
    let bytes = archive
        .get("word/document.xml")
        .expect("word/document.xml present");
    String::from_utf8(bytes.to_vec()).expect("document.xml utf-8")
}

/// Parse the bytes, re-serialize via the default export, and return the resulting
/// `word/document.xml`. For an UNEDITED document this reflects stemma's
/// verbatim-preservation contract (see header methodology note).
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

/// Assert the package opens clean (validate reports no errors).
fn assert_opens_clean(bytes: &[u8], rule: &str) {
    let report = stemma::api::validate(bytes);
    assert!(
        report.ok,
        "{rule} — validate must report no errors (Word opens without repair); issues: {:?}",
        report.issues
    );
}

