#[test]
fn sectpr_rtlgutter_emitted_after_cols_before_docgrid() {
    // ECMA-376 Annex A (EG_SectPrContents); ISO 29500-1 §17.6.16; ECMA-376 §17.6.16.
    // EG_SectPrContents is an xsd:sequence: pgMar < cols < rtlGutter < docGrid.
    // A schema-faithful serializer must emit children in that relative order.
    let body = r#"<w:p><w:r><w:t>body</w:t></w:r></w:p><w:sectPr><w:pgSz w:w="12240" w:h="15840"/><w:pgMar w:top="1440" w:right="1440" w:bottom="1440" w:left="1440" w:header="720" w:footer="720" w:gutter="720"/><w:cols w:space="720"/><w:rtlGutter/><w:docGrid w:linePitch="360"/></w:sectPr>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    // xmlRegex "<w:pgMar[^>]*/>.*<w:cols[^>]*/>.*<w:rtlGutter[^>]*/>.*<w:docGrid"
    // — no regex crate available, so translated to ordered-position contains
    // checks over the four element starts (the ordering invariant, not literal
    // self-closing syntax). Refs: EG_SectPrContents xsd:sequence; §17.6.16.
    let p_pgmar = xml.find("<w:pgMar");
    let p_cols = xml.find("<w:cols");
    let p_rtl = xml.find("<w:rtlGutter");
    let p_grid = xml.find("<w:docGrid");
    assert!(
        p_pgmar.is_some() && p_cols.is_some() && p_rtl.is_some() && p_grid.is_some(),
        "EG_SectPrContents ordering (Annex A; §17.6.16) — expected all of pgMar/cols/rtlGutter/docGrid present in re-serialized XML; got pgMar={p_pgmar:?} cols={p_cols:?} rtlGutter={p_rtl:?} docGrid={p_grid:?}"
    );
    let (p_pgmar, p_cols, p_rtl, p_grid) = (
        p_pgmar.unwrap(),
        p_cols.unwrap(),
        p_rtl.unwrap(),
        p_grid.unwrap(),
    );
    assert!(
        p_pgmar < p_cols && p_cols < p_rtl && p_rtl < p_grid,
        "EG_SectPrContents is an xsd:sequence with order pgMar < cols < rtlGutter < docGrid (Annex A; ISO 29500-1 §17.6.16; ECMA-376 §17.6.16); a schema-faithful serializer must emit them in that order, got positions pgMar={p_pgmar} cols={p_cols} rtlGutter={p_rtl} docGrid={p_grid} in: {xml}"
    );

    assert_opens_clean(
        &b,
        "Correctly ordered sectPr children are schema-valid (EG_SectPrContents; §17.6.16); Word opens without repair",
    );
}

#[test]
fn pgsz_orient_landscape_authoritative_dims_not_swapped() {
    // ISO 29500-1 §17.6.13; ECMA-376 §17.18.65 (ST_PageOrientation).
    // orient=landscape with portrait-shaped dims (w<h) is valid; orient is a
    // layout flag applied on top of literal w/h (consumption swaps for the
    // physical page only), so the file opens clean.
    let body = r#"<w:p><w:r><w:t>body</w:t></w:r></w:p><w:sectPr><w:pgSz w:w="12240" w:h="15840" w:orient="landscape"/><w:pgMar w:top="1440" w:right="1440" w:bottom="1440" w:left="1440" w:header="720" w:footer="720" w:gutter="0"/></w:sectPr>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "orient=landscape with w<h is valid (orient optional, portrait implied when absent; ISO 29500-1 §17.6.13, ST_PageOrientation §17.18.65); Word opens without repair",
    );
}

#[test]
fn pgsz_code_is_label_only_does_not_set_dimensions() {
    // ISO 29500-1 §17.6.13; MS-OI29500 §2.1.220; ECMA-376 §17.18.10.
    // code is a paper-size LABEL only; with explicit w/h present, geometry comes
    // from w/h regardless of code, and consuming the doc yields unchanged prose.
    let body = r#"<w:p><w:r><w:t>body</w:t></w:r></w:p><w:sectPr><w:pgSz w:w="12240" w:h="15840" w:code="1"/><w:pgMar w:top="1440" w:right="1440" w:bottom="1440" w:left="1440" w:header="720" w:footer="720" w:gutter="0"/></w:sectPr>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "code=1 is within Word's 0..118 range (MS-OI29500 §2.1.220) and w/h are explicit (§17.6.13); the section is valid, Word opens without repair",
    );
    let accepted = Document::parse(&b)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text();
    assert_eq!(
        accepted.trim(),
        "body",
        "code is a label only and changes no content (ISO 29500-1 §17.6.13: code 'does not itself determine the paper size'); accepting the document yields the unchanged body text"
    );
}

#[test]
fn negative_top_margin_preserved_and_opens_clean() {
    // ECMA-376 §17.6.11; ISO 29500-1 §17.6.11; ISO 29500-1 §17.18.81; MS-OI29500 §2.1.555.
    // top is ST_SignedTwipsMeasure; a negative top is a documented Word layout
    // instruction (main story overlaps header). stemma must re-emit -720 verbatim.
    let body = r#"<w:p><w:r><w:t>Body</w:t></w:r></w:p><w:sectPr><w:pgSz w:w="12240" w:h="15840"/><w:pgMar w:top="-720" w:right="1440" w:bottom="1440" w:left="1440" w:header="1440" w:footer="720" w:gutter="0"/></w:sectPr>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:top="-720""#),
        "top is ST_SignedTwipsMeasure (§17.18.81) and the negative value is a documented Word layout instruction (§17.6.11); the verbatim-preserved body sectPr must re-emit the exact signed token w:top=\"-720\", not abs/zero/drop it; got: {xml}"
    );
    assert_opens_clean(
        &b,
        "ECMA §17.6.11 presents <w:pgMar w:top=\"-720\"/> as valid Word markup and MS-OI §2.1.555 confirms Word reads signed 32-bit values; validate must report no errors",
    );
}

#[test]
fn gutter_over_word_max_preserved_not_clamped() {
    // MS-OI29500 §2.1.218; ISO 29500-1 §17.6.11; ECMA-376 §17.6.11.
    // gutter is unsignedLong; 40000 (> Word's 31680 load-clamp) is schema-valid.
    // Word clamps on LOAD, not on save — stemma must NOT pre-emptively clamp;
    // the verbatim value must survive round-trip and the doc opens clean.
    let body = r#"<w:p><w:r><w:t>Body</w:t></w:r></w:p><w:sectPr><w:pgSz w:w="12240" w:h="15840"/><w:pgMar w:top="1440" w:right="1440" w:bottom="1440" w:left="1440" w:header="720" w:footer="720" w:gutter="40000"/></w:sectPr>"#;
    let b = make_docx(body, &[]);
    // Verbatim-preservation post-condition: stemma must not silently clamp the
    // authored value on save (CLAUDE.md no-silent-fallback). The serializer
    // round-trips untouched section markup, so the authored gutter must persist.
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:gutter="40000""#),
        "gutter is unsignedLong (MS-OI §2.1.218); 40000 is schema-valid and Word clamps only on LOAD, never rewriting the markup on save. stemma must preserve the authored value verbatim, not clamp to 31680 (no-silent-fallback); got: {xml}"
    );
    assert_opens_clean(
        &b,
        "gutter is unsignedLong (MS-OI §2.1.218) so 40000 is schema-valid; Word clamps on load rather than refusing, so validate must report no errors",
    );
}

#[test]
fn pgsz_code_over_118_preserved_and_opens_clean() {
    // MS-OI29500 §2.1.220; ISO 29500-1 §17.6.13; ISO 29500-1 §17.18.10.
    // code=240 (> Word's 0..118 load-clamp) is descriptive metadata only; w/h
    // govern geometry. stemma must preserve it verbatim; the doc opens clean.
    let body = r#"<w:p><w:r><w:t>Body</w:t></w:r></w:p><w:sectPr><w:pgSz w:w="12240" w:h="15840" w:code="240"/><w:pgMar w:top="1440" w:right="1440" w:bottom="1440" w:left="1440" w:header="720" w:footer="720" w:gutter="0"/></w:sectPr>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:code="240""#),
        "code is descriptive only (ECMA §17.6.13: 'does not itself determine the paper size'); Word's 0..118 cap (MS-OI §2.1.220) is a LOAD restriction, not a save rewrite. stemma must preserve the authored code=240 verbatim, neither dropping nor clamping it; got: {xml}"
    );
    assert_opens_clean(
        &b,
        "code does not determine page size (ECMA §17.6.13) and w/h are valid; an out-of-range descriptive code does not make Word repair, so validate reports no errors",
    );
}

#[test]
fn absent_pgsz_pgmar_not_synthesized() {
    // ISO 29500-1 §17.6.13; ISO 29500-1 §17.6.11; ECMA-376 §17.6.13.
    // pgSz/pgMar are optional CT_SectPr children. When a section declares
    // neither, stemma must NOT fabricate a default page size / margins on save
    // (silent fallback); the bare sectPr is preserved as authored.
    let body = r#"<w:p><w:r><w:t>Body</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        !xml.contains("<w:pgSz"),
        "pgSz is an optional CT_SectPr child (§17.6.13); a section that declared none must not gain a synthesized pgSz on save (no-silent-fallback: inventing Letter/A4 the author never wrote). Verbatim preservation must emit no <w:pgSz>; got: {xml}"
    );
    assert!(
        !xml.contains("<w:pgMar"),
        "pgMar is an optional CT_SectPr child (§17.6.11); a section that declared none must not gain synthesized margins on save (no-silent-fallback). Verbatim preservation must emit no <w:pgMar>; got: {xml}"
    );
    assert_opens_clean(
        &b,
        "a bare sectPr with no pgSz/pgMar is valid markup; Word supplies layout defaults itself (§17.6.13/§17.6.11), so validate must report no errors",
    );
}

#[test]
fn pgmar_negative_top_bottom_opens_clean() {
    // ISO 29500-1 §17.6.11; MS-OI29500 §2.1.218; ECMA-376 §17.18.81.
    // top/bottom are ST_SignedTwipsMeasure; Word's accepted floor is -31680.
    // Negative top/bottom is layout-only (overlap header/footer), so prose is
    // unaffected: accept == reject == the single paragraph.
    let body = r#"<w:p><w:r><w:t>Overlap header and footer.</w:t></w:r></w:p><w:sectPr><w:pgSz w:w="12240" w:h="15840"/><w:pgMar w:top="-720" w:bottom="-720" w:left="1440" w:right="1440" w:header="1440" w:footer="1440" w:gutter="0"/></w:sectPr>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "top/bottom are ST_SignedTwipsMeasure (§17.18.81) and Word's accepted floor is -31680 (MS-OI §2.1.218); a negative top/bottom (-720) is within Word's domain, so validate must report no errors",
    );
    let doc = Document::parse(&b).expect("parse");
    let accepted = doc.read_accepted().expect("read_accepted").to_text();
    assert_eq!(
        accepted.trim(),
        "Overlap header and footer.",
        "negative top/bottom is purely layout (text overlaps header/footer per §17.6.11); it must not mutate prose, so accepted text equals the single paragraph"
    );
    let rejected = doc.read_rejected().expect("read_rejected").to_text();
    assert_eq!(
        rejected.trim(),
        "Overlap header and footer.",
        "no tracked change is present; rejected text equals accepted text and the visible prose is unaffected by margin sign (§17.6.11)"
    );
}

#[test]
fn pgsz_code_above_word_max_118_opens_clean() {
    // ISO 29500-1 §17.6.13; MS-OI29500 §2.1.220.
    // code=999 (> Word's 0..118) is a label-only identifier that never sets
    // geometry; w/h govern size. Word clamps/ignores on load, opens clean, and
    // prose is unchanged.
    let body = r#"<w:p><w:r><w:t>Letter page with an oversized paper code.</w:t></w:r></w:p><w:sectPr><w:pgSz w:w="12240" w:h="15840" w:code="999"/><w:pgMar w:top="1440" w:bottom="1440" w:left="1440" w:right="1440" w:header="720" w:footer="720" w:gutter="0"/></w:sectPr>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "code is label-only; an out-of-range code (999 > Word's max 118, MS-OI §2.1.220) does not affect geometry and is clamped/ignored on load, so validate must report no errors",
    );
    let accepted = Document::parse(&b)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text();
    assert_eq!(
        accepted.trim(),
        "Letter page with an oversized paper code.",
        "code never determines page size and is descriptive only (§17.6.13); it cannot mutate prose, so accepted text equals the single paragraph"
    );
}

#[test]
fn pgsz_code_only_without_w_h_has_no_meaning() {
    // ISO 29500-1 §17.6.13.
    // A code-only pgSz (no w/h) 'has no meaning' for size; Word falls back to
    // default geometry, the file opens clean, and prose is unchanged.
    let body = r#"<w:p><w:r><w:t>Code only, no dimensions.</w:t></w:r></w:p><w:sectPr><w:pgSz w:code="1"/><w:pgMar w:top="1440" w:bottom="1440" w:left="1440" w:right="1440" w:header="720" w:footer="720" w:gutter="0"/></w:sectPr>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "all CT_PageSz attributes are optional and a code-only pgSz 'has no meaning' for size (§17.6.13); Word falls back to default geometry, so validate reports no errors",
    );
    let accepted = Document::parse(&b)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text();
    assert_eq!(
        accepted.trim(),
        "Code only, no dimensions.",
        "a meaningless code-only pgSz (w/h omitted, §17.6.13) cannot mutate prose; accepted text equals the single paragraph"
    );
}
